using System.Collections;
using UnityEngine;

/// <summary>
/// Espírito de animal preso no mundo, com fluxo próprio de resgate (item 14
/// da auditoria): até agora, libertar animais só existia como
/// <see cref="Action_FreeAnimal"/> (acção de diálogo/NPC), sem um componente
/// dedicado de "tocar -> sequência de resgate -> guardar".
///
/// Fluxo ao tocar no espírito (trigger, tag "Player" — mesmo padrão de
/// <see cref="PickupBase"/>/<see cref="SafeHaven"/>):
/// 1. Bloqueia o movimento do player e cancela habilidades "com estado"
///    (mesmo padrão de Action_SetPlayerMovementLocked).
/// 2. Toca animação/VFX/SFX de libertação e aguarda <see cref="releaseDuration"/>.
/// 3. Liberta o animal (<see cref="PlayerProgress.FreeAnimal"/>) e desbloqueia
///    a forma em FormSwitcher — dispara <see cref="PlayerProgress.AnimalUnlocked"/>,
///    que o <see cref="NewAnimalUnlockedUI"/> já mostra automaticamente
///    (Tarefa #8).
/// 4. Devolve o controlo ao player.
/// 5. Autosave (<see cref="SaveManager.SaveAutosave"/>).
/// 6. Remove o espírito da cena.
///
/// Anti-duplicação: usa <see cref="PlayerProgress.HasFreedAnimal"/> — se o
/// animal já foi libertado (save anterior), este objecto desactiva-se em
/// Start() e nunca repete o resgate.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class AnimalSpiritRescue : MonoBehaviour
{
    [Header("Animal")]
    [Tooltip("Forma a libertar/desbloquear ao resgatar este espírito.")]
    public AnimalFormData form;

    [Tooltip("Se activo, também desbloqueia a forma em FormSwitcher.unlockedForms (necessário para o player a poder usar de imediato). Ver Action_FreeAnimal.")]
    public bool unlockForSwitching = true;

    [Header("Sequência de resgate")]
    [Tooltip("Duração (segundos) da animação/VFX de libertação, durante a qual o player fica com o movimento bloqueado.")]
    public float releaseDuration = 1.2f;

    [Tooltip("Som tocado ao iniciar o resgate.")]
    public AudioClip releaseSfx;

    [Tooltip("Prefab de efeito visual instanciado na posição do espírito ao iniciar o resgate (opcional — partículas, brilho, etc.).")]
    public GameObject releaseVfxPrefab;

    [Tooltip("Motivo passado a AbilityRouter.CancelAll ao bloquear o movimento — ver Action_SetPlayerMovementLocked (por omissão, Dialogue: cutscene de resgate).")]
    public AbilityCancelReason cancelReason = AbilityCancelReason.Dialogue;

    [Header("Autosave")]
    [Tooltip("Se activo, chama SaveManager.SaveAutosave() no fim da sequência — resgatar um animal é progresso irreversível, tal como libertar via diálogo (ver Action_Autosave).")]
    public bool autosaveOnRescue = true;

    private bool _rescuing;
    private bool _rescued;

    private void Awake()
    {
        var col = GetComponent<Collider2D>();
        if (col != null) col.isTrigger = true;
    }

    private void Start()
    {
        // Já libertado num save anterior -> não voltar a aparecer nem repetir.
        if (form != null && PlayerProgress.Instance != null
            && PlayerProgress.Instance.HasFreedAnimal(form.formId))
        {
            _rescued = true;
            gameObject.SetActive(false);
        }
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;
        TryRescue(other.gameObject);
    }

    /// <summary>Inicia a sequência de resgate (idempotente — ignora se já em curso ou concluída).</summary>
    public void TryRescue(GameObject player)
    {
        if (_rescuing || _rescued || form == null || player == null) return;

        _rescuing = true;
        StartCoroutine(RescueRoutine(player));
    }

    private IEnumerator RescueRoutine(GameObject player)
    {
        // 1. Bloquear controlos + cancelar habilidades "com estado" do player.
        var motor = player.GetComponent<PlayerMotor2D>();
        var abilityRouter = player.GetComponent<AbilityRouter>();

        motor?.SetMovementLocked(true, this);
        abilityRouter?.CancelAll(cancelReason);

        // 2. Animação/VFX/SFX de libertação.
        if (releaseVfxPrefab != null)
            Instantiate(releaseVfxPrefab, transform.position, Quaternion.identity);

        AudioManager.Instance?.PlaySEAtPoint(releaseSfx, transform.position);

        if (releaseDuration > 0f)
            yield return new WaitForSeconds(releaseDuration);

        // 3. Adicionar a forma ao progresso — dispara AnimalUnlocked
        // (NewAnimalUnlockedUI mostra-se automaticamente, Tarefa #8).
        PlayerProgress.Instance?.FreeAnimal(form);

        if (unlockForSwitching)
        {
            var switcher = player.GetComponent<FormSwitcher>();
            switcher?.UnlockForm(form);
        }

        // 4. Devolver o controlo ao player (mesma "source" do bloqueio).
        motor?.SetMovementLocked(false, this);

        // 5. Guardar o resgate.
        if (autosaveOnRescue)
            SaveManager.Instance?.SaveAutosave();

        // 6. Remover o espírito da cena.
        _rescuing = false;
        _rescued = true;
        gameObject.SetActive(false);
        Destroy(gameObject);
    }
}
